import{_ as a,o as i,c as r,ag as l}from"./chunks/framework.OsDJF_Ea.js";const m=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"about/roadmap.md","filePath":"about/roadmap.md"}'),t={name:"about/roadmap.md"};function o(s,e,n,d,c,h){return i(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>Planned features and improvements for InspoSearch, roughly ordered by priority.</p><h2 id="in-progress" tabindex="-1">In Progress <a class="header-anchor" href="#in-progress" aria-label="Permalink to &quot;In Progress&quot;">​</a></h2><ul><li>Documentation site — this site</li><li>Source health dashboard — live status page showing which APIs are up/down</li></ul><h2 id="planned-—-near-term" tabindex="-1">Planned — Near Term <a class="header-anchor" href="#planned-—-near-term" aria-label="Permalink to &quot;Planned — Near Term&quot;">​</a></h2><ul><li>Save collections — bookmark images to named collections stored in localStorage</li><li>Download queue — batch download selected images with attribution metadata</li><li>Search history — recent queries stored locally with one-click re-search</li><li>Advanced filters — date range, medium type, source category toggles in search bar</li><li>Localisation — interface translations starting with FR, DE, ES, NL, JA</li></ul><h2 id="planned-—-medium-term" tabindex="-1">Planned — Medium Term <a class="header-anchor" href="#planned-—-medium-term" aria-label="Permalink to &quot;Planned — Medium Term&quot;">​</a></h2><ul><li>Similar image search — reverse image search using perceptual hashing</li><li>Shareable links — URL-encoded search state for sharing queries and results</li><li>Browser extension — right-click &quot;Search InspoSearch&quot; on any web image</li><li>PWA — installable progressive web app with offline search history</li><li>Source plugins — user-submitted source manifests loadable from URL/JSON</li></ul><h2 id="exploring" tabindex="-1">Exploring <a class="header-anchor" href="#exploring" aria-label="Permalink to &quot;Exploring&quot;">​</a></h2><ul><li>Collaborative collections — shared collections via CRDTs (no server)</li><li>Public API — JSON API for programmatic access to InspoSearch queries</li><li>Embed widget — embeddable search widget for museum/archive websites</li><li>Mobile app — native wrapper with offline caching</li></ul><h2 id="completed" tabindex="-1">Completed <a class="header-anchor" href="#completed" aria-label="Permalink to &quot;Completed&quot;">​</a></h2><ul><li>AI research assistant with Gemini/Claude/OpenAI/Ollama (v1.5.0)</li><li>Interpret: cross-reference (v1.5.0)</li><li>3D constellation view (v1.5.0)</li><li>Board view (v1.4.0)</li><li>Colour extraction (v1.4.0)</li><li>Deep zoom via IIIF/OpenSeadragon (v1.4.0)</li><li>Exact/explore search modes (v1.3.0)</li><li>Detail view with keyboard navigation (v1.1.0)</li><li>Reactive state management (v1.2.0)</li><li>Rate limiter for source manifests (v1.3.0)</li><li>500+ sources (v1.5.0)</li></ul><h2 id="suggesting-features" tabindex="-1">Suggesting Features <a class="header-anchor" href="#suggesting-features" aria-label="Permalink to &quot;Suggesting Features&quot;">​</a></h2><p><a href="https://github.com/insposearch/insposearch/issues/new" target="_blank" rel="noreferrer">Open an issue</a> with the <code>feature-request</code> label.</p>',14)])])}const p=a(t,[["render",o]]);export{m as __pageData,p as default};
